{
  "name": "temporal-counter-ts",
  "private": true,
  "version": "1.0.0",
  "scripts": {
    "worker": "tsx src/worker.ts",
    "client": "tsx src/client.ts",
    "start": "concurrently --kill-others -s first -n worker,client \"npm run worker\" \"npm run client\""
  },
  "dependencies": {
    "@temporalio/activity": "^1.11.6",
    "@temporalio/client": "^1.11.6",
    "@temporalio/worker": "^1.11.6",
    "@temporalio/workflow": "^1.11.6"
  },
  "devDependencies": {
    "concurrently": "^9.0.1",
    "tsx": "^4.19.2",
    "typescript": "^5.6.3"
  }
}

import { condition, defineSignal, setHandler } from "@temporalio/workflow";

export const incrementSignal = defineSignal<[number]>("increment");
export const finishSignal = defineSignal("finish");

export async function CounterWorkflow(): Promise<number> {
  let counter = 0;
  let done = false;

  setHandler(incrementSignal, (value) => {
    counter += value;
  });

  setHandler(finishSignal, () => {
    done = true;
  });

  await condition(() => done);
  return counter;
}

import { NativeConnection, Worker } from "@temporalio/worker";

const taskQueue = "counter-ts";

async function run(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!address || !apiKey || !namespace) {
    throw new Error("Missing TEMPORAL_ADDRESS, TEMPORAL_API_KEY, or TEMPORAL_NAMESPACE env vars.");
  }

  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue,
    workflowsPath: require.resolve("./workflows"),
  });

  await worker.run();
}

run().catch((error) => {
  console.error("Worker failed:", error);
  process.exit(1);
});

import { Client, Connection } from "@temporalio/client";
import { CounterWorkflow, finishSignal, incrementSignal } from "./workflows";

const taskQueue = "counter-ts";

async function run(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId = process.env.ZEALT_RUN_ID;

  if (!address || !apiKey || !namespace || !runId) {
    throw new Error(
      "Missing TEMPORAL_ADDRESS, TEMPORAL_API_KEY, TEMPORAL_NAMESPACE, or ZEALT_RUN_ID env vars."
    );
  }

  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({
    connection,
    namespace,
  });

  const workflowId = `counter-wf-${runId}`;

  const handle = await client.workflow.start(CounterWorkflow, {
    taskQueue,
    workflowId,
  });

  await handle.signal(incrementSignal, 5);
  await handle.signal(incrementSignal, 3);
  await handle.signal(incrementSignal, 2);
  await handle.signal(finishSignal);

  const result = await handle.result();
  console.log(result);
}

run().catch((error) => {
  console.error("Client failed:", error);
  process.exit(1);
});
